import { Injectable } from '@angular/core';
import { environment } from 'src/environments/environment';
import { Observable, of, throwError, forkJoin, ObservableInput} from 'rxjs';
import {catchError, retry, tap} from 'rxjs/operators';
import {
  HttpClient,
  HttpParams,
  HttpHeaders,
  HttpErrorResponse,
} from '@angular/common/http';
import {ApiNameConstants} from '../constant/ApiNameConstants';
import {UtilsService} from '../helper/service/utils.service';
import {ErrorHandlerService} from 'src/app/common/ErrorHandlerService';
import {AuthService} from 'src/app/core/auth/auth.service';
import {ApiModel} from "../model/ApiModel";
import {ConstantsApp} from "../constant/ConstantsApp";

@Injectable({
  providedIn: 'root',
})
export class CommonService {
  constructor(
    private http: HttpClient,
    private utilsService: UtilsService,
    private authService: AuthService,
    private errorHandlerService: ErrorHandlerService
  ) {
  }

  public getData(
    apiUrl: any,
    functionName: any,
    messageLog: any
  ): Observable<any> {
    return this.http.get(apiUrl).pipe(
      tap((_) => this.errorHandlerService.log(messageLog, functionName)),
      catchError(
        this.errorHandlerService.handleError<any>(messageLog, [], functionName)
      )
    );
  }

  // Thêm method mới để hỗ trợ headers
  public postWithHeaders(
    url: string, 
    body: any, 
    headers: HttpHeaders
  ): Observable<any> {
    return this.http.post(url, JSON.stringify(body), { headers }).pipe(
      tap((_) => this.errorHandlerService.log('API call with headers', 'postWithHeaders')),
      catchError(
        this.errorHandlerService.handleError<any>('postWithHeaders', [], 'postWithHeaders')
      )
    );
  }

  // Thêm method GET với headers
  public getWithHeaders(
    url: string, 
    headers: HttpHeaders
  ): Observable<any> {
    return this.http.get(url, { headers }).pipe(
      tap((_) => this.errorHandlerService.log('GET call with headers', 'getWithHeaders')),
      catchError(
        this.errorHandlerService.handleError<any>('getWithHeaders', [], 'getWithHeaders')
      )
    );
  }

  // Update retrieveData để hỗ trợ headers
  public retrieveDataWithAuth(apiModels: ApiModel[], headers: HttpHeaders): Observable<any> {
    let arr: any = [];
    apiModels.forEach(item => {
      let call;
      if (item.method == ConstantsApp.GET) {
        call = this.http.get(item.uri, { headers }).pipe(
          tap((_) => this.errorHandlerService.log(item.messageLog, null)),
          catchError(
            this.errorHandlerService.handleError<any>(item.messageLog, [], null)
          )
        );
      } else {
        call = this.http.post<string>(item.uri, JSON.stringify(item.body), { headers }).pipe (
          tap(_ => this.errorHandlerService.log(item.messageLog, 'retrieveDataWithAuth')),
          catchError(this.errorHandlerService.handleError<any>('retrieveDataWithAuth', [], 'retrieveDataWithAuth'))
        );
      }
      arr.push(call);
    })
    return forkJoin(arr);
  }

  public getAllProvince(): Observable<any> {
    let apiUrl = environment.API_URI + ApiNameConstants.BS_GET_ALL_PROVINCES;
    return this.http.get<string>(apiUrl);
  }

  public getDistrictsByProvince(provinceCode: any): Observable<any> {
    let apiUrl =
      environment.API_URI +
      ApiNameConstants.BS_GET_DISTRICS_BY_PROVINCE +
      provinceCode;
    return this.http.get<string>(apiUrl);
  }

  public getWardsByDistrict(districtCode: any): Observable<any> {
    let apiUrl =
      environment.API_URI +
      ApiNameConstants.BS_GET_WARDS_BY_DISTRICT +
      districtCode;
    return this.http.get<string>(apiUrl);
  }

  geocodeAddress(address: string) {
    // API endpoint for the Geocoding API
    const url = `https://maps.googleapis.com/maps/api/geocode/json?address=${encodeURIComponent(
      address
    )}&key=AIzaSyDYp_QqhpBXUJ_qYDts8AQe5BWtIFO8dW8`;

    // Make an HTTP GET request to the API
    return this.http.get(url);
  }

  public postDatas(
    body: any,
    apiUrl: any,
    functionName: any,
    messageLog: any
  ): Observable<any> {
    return this.http.post<string>(apiUrl, JSON.stringify(body)).pipe(
      tap((_) => this.errorHandlerService.log(messageLog, functionName)),
      catchError(
        this.errorHandlerService.handleError<any>(messageLog, [], functionName)
      )
    );
  }

  public getFile(
    body: any,
    apiUrl: any,
    functionName: any,
    messageLog: any
  ): Observable<any> {
    const options = { responseType: 'arraybuffer' as 'json' };
    return this.http.post<string>(apiUrl, JSON.stringify(body), options).pipe(
      tap((_) => this.errorHandlerService.log(messageLog, functionName)),
      catchError(
        this.errorHandlerService.handleError<any>(messageLog, [], functionName)
      )
    );
  }

  public retrieveData(apiModels: ApiModel[]): Observable<any> {
    let arr: any = [];
    apiModels.forEach(item => {
      let call;
      if (item.method == ConstantsApp.GET) {
        call = this.http.get(item.uri).pipe(
          tap((_) => this.errorHandlerService.log(item.messageLog, null)),
          catchError(
            this.errorHandlerService.handleError<any>(item.messageLog, [], null)
          )
        );
      } else {
        call = this.http.post<string>(item.uri, JSON.stringify(item.body)).pipe (
          tap(_ => this.errorHandlerService.log(item.messageLog, 'retrieveData')),
          catchError(this.errorHandlerService.handleError<any>('retrieveData', [], 'retrieveData'))
        );
      }
      arr.push(call);
    })
     return forkJoin(arr);
    //return arr;
  }
  
  public downloadCv(item: any) {
    console.log('onDownloadCv item: ', item);
    // if (!item.cv) return;
    const body = {
      fileName: item.cv,
      freelancerId: item.freelancerId
    };
    const functionName = 'onDownloadCv';
    const messageLog = 'download cv';
    const apiUrl = environment.API_URI + ApiNameConstants.BS_USER_FILE_DOWNLOAD
    this.getFile(body, apiUrl, functionName, messageLog)
      .subscribe((res: any) => {
        if (res) {
          const blob = new Blob([res], { type: 'application/octet-stream' });
          const url = window.URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = item.cv;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
        }
      });
  }
}
